  const rab = CreateResizableArrayBuffer(4 * ctor.BYTES_PER_ELEMENT, 8 * ctor.BYTES_PER_ELEMENT);
  const fixedLength = new ctor(rab, 0, 4);
  const fixedLengthWithOffset = new ctor(rab, 2 * ctor.BYTES_PER_ELEMENT, 2);
  const lengthTracking = new ctor(rab, 0);
  const lengthTrackingWithOffset = new ctor(rab, 2 * ctor.BYTES_PER_ELEMENT);

  // Write some data into the array.
  const taWrite = new ctor(rab);
  for (let i = 0; i < 4; ++i) {
    taWrite[i] = MayNeedBigInt(taWrite, 2 * i);
  }

  // Orig. array: [0, 2, 4, 6]
  //              [0, 2, 4, 6] << fixedLength
  //                    [4, 6] << fixedLengthWithOffset
  //              [0, 2, 4, 6, ...] << lengthTracking
  //                    [4, 6, ...] << lengthTrackingWithOffset

  function isTwoOrFour(n) {
    return n == 2 || n == 4;
  }
  console.log(Number(Array.prototype.find.call(fixedLength, isTwoOrFour)));
  console.log(Number(Array.prototype.find.call(fixedLengthWithOffset, isTwoOrFour)));
  console.log(Number(Array.prototype.find.call(lengthTracking, isTwoOrFour)));
  console.log(Number(Array.prototype.find.call(lengthTrackingWithOffset, isTwoOrFour)));

  // Shrink so that fixed length TAs go out of bounds.
  rab.resize(3 * ctor.BYTES_PER_ELEMENT);

  // Orig. array: [0, 2, 4]
  //              [0, 2, 4, ...] << lengthTracking
  //                    [4, ...] << lengthTrackingWithOffset

  console.log(Array.prototype.find.call(fixedLength, isTwoOrFour));
  console.log(Array.prototype.find.call(fixedLengthWithOffset, isTwoOrFour));

  console.log(Number(Array.prototype.find.call(lengthTracking, isTwoOrFour)));
  console.log(Number(Array.prototype.find.call(lengthTrackingWithOffset, isTwoOrFour)));

  // Shrink so that the TAs with offset go out of bounds.
  rab.resize(1 * ctor.BYTES_PER_ELEMENT);
  console.log(Array.prototype.find.call(fixedLength, isTwoOrFour));
  console.log(Array.prototype.find.call(fixedLengthWithOffset, isTwoOrFour));
  console.log(Array.prototype.find.call(lengthTrackingWithOffset, isTwoOrFour));

  console.log(Array.prototype.find.call(lengthTracking, isTwoOrFour));

  // Shrink to zero.
