  console.log(Array.prototype.find.call(fixedLength, isTwoOrFour));
  console.log(Array.prototype.find.call(fixedLengthWithOffset, isTwoOrFour));
  console.log(Array.prototype.find.call(lengthTrackingWithOffset, isTwoOrFour));

