  console.log(Array.prototype.find.call(fixedLengthWithOffset, isTwoOrFour));
  console.log(Number(Array.prototype.find.call(lengthTracking, isTwoOrFour)));
  console.log(Number(Array.prototype.find.call(lengthTrackingWithOffset, isTwoOrFour)));
}
