  console.log(Array.prototype.lastIndexOf.call(fixedLengthWithOffset, n0));
  console.log(Array.prototype.lastIndexOf.call(lengthTrackingWithOffset, n0));

  console.log(Array.prototype.lastIndexOf.call(lengthTracking, n0));
  console.log(Array.prototype.lastIndexOf.call(lengthTracking, undefined));

