  valueOf() {
    return 3
  },
  toString() {
    return 1
  }
};
var push = obj.push();
console.log(push);

obj.length = {
  valueOf() {
    return 3
  },
  toString() {
    return {}
  }
};
var push = obj.push();
console.log(push);

try {
  obj.length = {
    valueOf() {
      return 3
    },
    toString() {
      throw "error"
    }
  };
  var push = obj.push();
  console.log(push);
}
catch (e) {
  console.log(e);
}

obj.length = {
  toString() {
    return 1
  }
};
var push = obj.push();
console.log(push);

obj.length = {
  valueOf() {
    return {}
  },
  toString() {
    return 1
  }
}
var push = obj.push();
console.log(push);

try {

  obj.length = {
    valueOf() {
      throw "error"
    },
    toString() {
      return 1
    }
  };
  var push = obj.push();
  throw new Test262Error('#7.1:  obj.length = {valueOf() {throw "error"}, toString() {return 1}}; obj.push() throw "error". Actual: ' + (push));
}
catch (e) {
  console.log(e);
}

try {

  obj.length = {
    valueOf() {
      return {}
    },
    toString() {
      return {}
    }
  };
  var push = obj.push();
  throw new Test262Error('#8.1:  obj.length = {valueOf() {return {}}, toString() {return {}}}  obj.push() throw TypeError. Actual: ' + (push));
}
catch (e) {
  console.log(e instanceof TypeError);
}
}

