function main(): void {
for (let ctor of ctors) {
  const rab = CreateResizableArrayBuffer(4 * ctor.BYTES_PER_ELEMENT, 8 * ctor.BYTES_PER_ELEMENT);
  const fixedLength = new ctor(rab, 0, 4);
  const fixedLengthWithOffset = new ctor(rab, 2 * ctor.BYTES_PER_ELEMENT, 2);
  const lengthTracking = new ctor(rab, 0);
  const lengthTrackingWithOffset = new ctor(rab, 2 * ctor.BYTES_PER_ELEMENT);
  const taWrite = new ctor(rab);

  // toLocaleString separator is implementation dependent.
  function listToString(list) {
    const comma = ['',''].toLocaleString();
    return list.join(comma);
  }

  // Write some data into the array.
  for (let i = 0; i < 4; ++i) {
    taWrite[i] = MayNeedBigInt(taWrite, 2 * i);
  }

  // Orig. array: [0, 2, 4, 6]
  //              [0, 2, 4, 6] << fixedLength
  //                    [4, 6] << fixedLengthWithOffset
  //              [0, 2, 4, 6, ...] << lengthTracking
  //                    [4, 6, ...] << lengthTrackingWithOffset

  console.log(Array.prototype.toLocaleString.call(fixedLength));
  console.log(Array.prototype.toLocaleString.call(fixedLengthWithOffset));
  console.log(Array.prototype.toLocaleString.call(lengthTracking));
  console.log(Array.prototype.toLocaleString.call(lengthTrackingWithOffset));

  // Shrink so that fixed length TAs go out of bounds.
  rab.resize(3 * ctor.BYTES_PER_ELEMENT);

  // Orig. array: [0, 2, 4]
  //              [0, 2, 4, ...] << lengthTracking
  //                    [4, ...] << lengthTrackingWithOffset

  console.log(Array.prototype.toLocaleString.call(fixedLength));
  console.log(Array.prototype.toLocaleString.call(fixedLengthWithOffset));

  console.log(Array.prototype.toLocaleString.call(lengthTracking));
  console.log(Array.prototype.toLocaleString.call(lengthTrackingWithOffset));

  // Shrink so that the TAs with offset go out of bounds.
  rab.resize(1 * ctor.BYTES_PER_ELEMENT);
  console.log(Array.prototype.toLocaleString.call(fixedLength));
  console.log(Array.prototype.toLocaleString.call(fixedLengthWithOffset));
  console.log(Array.prototype.toLocaleString.call(lengthTrackingWithOffset));

  console.log(Array.prototype.toLocaleString.call(lengthTracking));

  // Shrink to zero.
  rab.resize(0);
  console.log(Array.prototype.toLocaleString.call(fixedLength));
  console.log(Array.prototype.toLocaleString.call(fixedLengthWithOffset));
  console.log(Array.prototype.toLocaleString.call(lengthTrackingWithOffset));

  console.log(Array.prototype.toLocaleString.call(lengthTracking));

  // Grow so that all TAs are back in-bounds.
  rab.resize(6 * ctor.BYTES_PER_ELEMENT);
  for (let i = 0; i < 6; ++i) {
